from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    # Group triples by subject to handle related entities (e.g., country info)
    subject_triples: dict[str, list[Triple]] = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Find the monument as the main subject (look for "Monument" in subject name)
    main_subject = None
    for subj in subject_triples.keys():
        if "Monument" in subj or "Memorial" in subj or "Plack" in subj:
            main_subject = subj
            break
    if main_subject is None:
        main_subject = triples[0].subject

    # Collect information for the main subject
    main_attributes: list[str] = []
    location_parts: list[str] = []
    country_name: str = ""
    capital_info: str = ""

    for subject, sub_triples in subject_triples.items():
        for triple in sub_triples:
            p = triple.predicate
            o = triple.object.strip('"')  # remove surrounding quotes if present

            # Map predicates to natural‑language fragments
            if subject == main_subject:
                if p == "category":
                    main_attributes.append(f"is a {o}")
                elif p in ("established", "foundingDate"):
                    main_attributes.append(f"was established on {o}")
                elif p == "inaugurationDate":
                    main_attributes.append(f"was inaugurated on {o}")
                elif p == "owner":
                    main_attributes.append(f"is owned by {o}")
                elif p == "owningOrganisation":
                    main_attributes.append(f"owned by {o}")
                elif p == "dedicatedTo":
                    main_attributes.append(f"is dedicated to {o}")
                elif p == "designer":
                    main_attributes.append(f"was designed by {o}")
                elif p == "material":
                    main_attributes.append(f"is made of {o}")
                elif p == "nativeName":
                    main_attributes.append(f'native name is "{o}"')
                elif p == "district":
                    main_attributes.append(f"in the district of {o}")
                elif p == "location":
                    location_parts.append(o)
                elif p == "municipality":
                    location_parts.append(o)
                elif p == "state":
                    location_parts.append(o)
                elif p == "country":
                    country_name = o
            else:
                # Handle related entity info - only include capital for location context
                if p == "capital":
                    capital_info = f"with capital {o}"

    # Build location phrase - avoid redundant "country" prefix
    location_phrase = ""
    if location_parts:
        # Clean up location parts (remove duplicates, handle hierarchy)
        unique_locations = []
        for loc in location_parts:
            if loc not in unique_locations:
                unique_locations.append(loc)
        location_phrase = ", ".join(unique_locations)

    # Build the sentence - create a single fluent sentence
    sentence_parts: list[str] = []
    sentence_parts.append(main_subject)

    # Add location if available
    if location_phrase:
        if country_name and country_name not in location_phrase:
            location_phrase += f", {country_name}"
        sentence_parts.append(f"is located in {location_phrase}")
        if capital_info:
            sentence_parts.append(capital_info)
    elif country_name:
        sentence_parts.append(f"is located in {country_name}")

    # Add main subject attributes
    if main_attributes:
        sentence_parts.extend(main_attributes)

    # Combine all parts into a single fluent sentence
    # Use appropriate connectors between parts
    if len(sentence_parts) == 1:
        return main_subject + "."

    result = sentence_parts[0]
    for i, part in enumerate(sentence_parts[1:], 1):
        if part.startswith("is located") or part.startswith("with capital"):
            result += f", {part}"
        elif i == len(sentence_parts) - 1 and len(sentence_parts) > 2:
            result += f", {part}"
        else:
            result += f", {part}"
    result += "."

    return result

# EVOLVE-BLOCK-END

